/**
 * lib/parse-cheatsheet.js
 *
 * Parses the *_Cheatsheet.md files generated by gen-batch.js.
 * Returns a structured object used by compare.js.
 */

'use strict';

const fs = require('fs');
const path = require('path');

// ── Helpers ───────────────────────────────────────────────────────────────────

function parseDollar(s) {
  if (!s) return null;
  const t = s.trim();
  if (t === '—' || t === '-' || t === '') return null;
  const num = parseFloat(t.replace(/[$,]/g, ''));
  return isNaN(num) ? null : num;
}

/** Extract bare text from `backtick value` or return null for *(none)* */
function extractCell(raw) {
  const t = raw.trim();
  const m = t.match(/`([^`]+)`/);
  if (m) return m[1].trim();
  if (t.includes('*(none)*') || t === '') return null;
  return t || null;
}

/** Split a markdown table row into trimmed cells (drops leading/trailing empty). */
function tableRow(line) {
  return line
    .split('|')
    .map(c => c.trim())
    .slice(1, -1);
}

function isSeparatorRow(line) {
  return /^\s*\|[\s|:-]+\|\s*$/.test(line);
}

function isHeaderRow(line) {
  return (
    line.includes('Contractor zone') ||
    line.includes('Sub-cat') ||
    line.includes('# |') ||
    /^\|\s*#\s*\|/.test(line)
  );
}

/**
 * Normalize a line-item status string to one of:
 *   'match' | 'modified' | 'missing' | 'added' | 'unknown'
 */
function normalizeStatus(raw) {
  const s = raw.trim();
  if (s === 'MATCH') return 'match';
  if (s.startsWith('MOD-')) return 'modified';
  if (s.startsWith('MISSING')) return 'missing';
  if (s.startsWith('ADDED')) return 'added';
  return 'unknown';
}

// ── Main parser ───────────────────────────────────────────────────────────────

/**
 * @param {string} filepath  Absolute path to *_Cheatsheet.md
 * @returns {CheatsheetData}
 */
function parseCheatsheet(filepath) {
  const content = fs.readFileSync(filepath, 'utf8');
  const lines = content.split('\n');

  const setId = path.basename(filepath, '_Cheatsheet.md');

  const result = {
    setId,
    contractorZones: [],
    adjusterZones: [],
    expectedPairings: [],
    lineItems: [],
    summary: {
      totalContractorItems: 0,
      totalAdjusterItems: 0,
      expectedMatch: 0,
      expectedModQty: 0,
      expectedModPrice: 0,
      expectedMissing: 0,
      expectedAdded: 0,
    },
  };

  let section = null;
  let subsection = null;
  let currentZone = null;

  for (const line of lines) {
    const trimmed = line.trim();

    // ── Section detection ──────────────────────────────────────────────────
    if (/^##\s+P1\s*\/\s*P2/.test(trimmed)) {
      section = 'zones';
      subsection = null;
      continue;
    }
    if (/^##\s+P3\s*—\s*Expected zone matches/.test(trimmed)) {
      section = 'zonePairings';
      continue;
    }
    if (/^##\s+P3\s*—\s*Line-item pairings/.test(trimmed)) {
      section = 'lineItems';
      continue;
    }
    if (/^##\s+Summary/.test(trimmed)) {
      section = 'summary';
      continue;
    }

    // ── Zones section ──────────────────────────────────────────────────────
    if (section === 'zones') {
      if (/^###\s+Contractor estimate/i.test(trimmed)) {
        subsection = 'contractor';
        continue;
      }
      if (/^###\s+Adjuster estimate/i.test(trimmed)) {
        subsection = 'adjuster';
        continue;
      }
      if (/^\d+\./.test(trimmed)) {
        const m = trimmed.match(/`([^`]+)`/);
        if (m) {
          if (subsection === 'contractor') result.contractorZones.push(m[1]);
          else if (subsection === 'adjuster') result.adjusterZones.push(m[1]);
        }
      }
    }

    // ── Zone pairings table ────────────────────────────────────────────────
    if (section === 'zonePairings' && trimmed.startsWith('|')) {
      if (isSeparatorRow(trimmed) || isHeaderRow(trimmed)) continue;
      const cells = tableRow(trimmed);
      if (cells.length < 3) continue;
      const contractor = extractCell(cells[0]);
      const adjuster = extractCell(cells[1]);
      const matchCell = cells[2];
      const isMatch = /\*\*MATCH\*\*/.test(matchCell) && !/NO MATCH/.test(matchCell);
      result.expectedPairings.push({ contractor, adjuster, match: isMatch });
    }

    // ── Line-item pairings section ─────────────────────────────────────────
    if (section === 'lineItems') {
      if (/^###\s+/.test(trimmed)) {
        const heading = trimmed.slice(4).trim();
        let contractorZone = null;
        let adjusterZone = null;
        let contractorOnly = false;
        let adjusterOnly = false;

        if (heading.includes(' / ')) {
          const slash = heading.indexOf(' / ');
          contractorZone = heading.slice(0, slash).trim();
          adjusterZone = heading.slice(slash + 3).trim();
        } else if (/\(contractor-only/i.test(heading)) {
          contractorZone = heading.replace(/\s*\(contractor-only[^)]*\)/i, '').trim();
          contractorOnly = true;
        } else if (/\(adjuster-only/i.test(heading)) {
          adjusterZone = heading.replace(/\s*\(adjuster-only[^)]*\)/i, '').trim();
          adjusterOnly = true;
        } else {
          contractorZone = heading;
        }

        currentZone = { contractorZone, adjusterZone, contractorOnly, adjusterOnly, items: [] };
        result.lineItems.push(currentZone);
        continue;
      }

      if (currentZone && trimmed.startsWith('|')) {
        if (isSeparatorRow(trimmed) || isHeaderRow(trimmed)) continue;
        const cells = tableRow(trimmed);
        if (cells.length < 7) continue;

        const num = parseInt(cells[0], 10);
        if (isNaN(num)) continue;

        const contractorDesc = cells[2].includes('*(none)*') ? null : cells[2].trim();
        const adjusterDesc = cells[3].includes('*(none)*') ? null : cells[3].trim();
        const rawStatus = cells[4].trim();
        const normalizedStatus = normalizeStatus(rawStatus);

        currentZone.items.push({
          num,
          subcat: cells[1].trim(),
          contractorDesc,
          adjusterDesc,
          rawStatus,
          normalizedStatus,
          contractorDollars: parseDollar(cells[5]),
          adjusterRcvDollars: parseDollar(cells[6]),
          gapDollars: parseDollar(cells[7] || ''),
        });
      }
    }

    // ── Summary section ────────────────────────────────────────────────────
    if (section === 'summary' && trimmed.startsWith('- **')) {
      const m = trimmed.match(/\*\*([^*]+)\*\*[^:]*:\s*(\d+)/);
      if (m) {
        const label = m[1].toLowerCase().trim();
        const val = parseInt(m[2], 10);
        if (label.includes('total contractor')) result.summary.totalContractorItems = val;
        else if (label.includes('total adjuster')) result.summary.totalAdjusterItems = val;
        else if (label.includes('expected match')) result.summary.expectedMatch = val;
        else if (label.includes('mod-qty')) result.summary.expectedModQty = val;
        else if (label.includes('mod-price')) result.summary.expectedModPrice = val;
        else if (label.includes('missing')) result.summary.expectedMissing = val;
        else if (label.includes('added')) result.summary.expectedAdded = val;
      }
    }
  }

  // Derived convenience counts
  result.summary.expectedModified =
    result.summary.expectedModQty + result.summary.expectedModPrice;
  result.summary.expectedTotal =
    result.summary.expectedMatch +
    result.summary.expectedModified +
    result.summary.expectedMissing +
    result.summary.expectedAdded;

  return result;
}

module.exports = { parseCheatsheet };
